/**
 * method
 * @name f_addDataSet
 * @description 매출항목조회 완료후 그리드에 ADD
 */
scwin.f_addDataSet = function (sellItemGubun) {
  if (!ds_resultsSellingItem.getRowCount()) {
    return;
  }
  if (sellItemGubun == "ONE") {
    let row = gr_results4.getFocusedRowIndex();
    if (row < 0) {
      return;
    }
    let sellingItem = ds_resultsSellingItem.getRowJSON(0);
    let rowObj = ds_results4.getRowJSON(row);
    sellingItem.eqKndCd = rowObj.eqKndCd;
    sellingItem.eqKndNm = rowObj.eqKndNm;
    sellingItem.eqNrmCd = rowObj.eqNrmCd;
    sellingItem.eqNrmNm = rowObj.eqNrmNm;
    sellingItem.checkBox = rowObj.checkBox;
    sellingItem.sellSeq = rowObj.sellSeq;
    ds_results4.setRowJSON(row, sellingItem, true);
    return;
  }
  let matched = null;
  let allSellingItems = ds_resultsSellingItem.getAllJSON();
  let doButtonDisable = false;
  let addItems = [];
  let results2Row = ds_results2.getRowJSON(gr_results2.getFocusedRowIndex());
  let results1Row = ds_results1.getRowJSON(gr_results1.getFocusedRowIndex());
  for (let sellingItem of allSellingItems) {
    //중복 첵크
    bAdd = true;
    matched = ds_results4.getMatchedIndex("sellItemCd", sellingItem.sellItemCd, true);
    if (matched.length) {
      continue;
    }
    doButtonDisable = true;
    sellingItem.checkBox = "T";

    // 기타하역료일 경우 할증율을 0으로 셋팅한다. (procedure에는 5.4로 셋팅하고 있음)
    if (sellingItem.sellItemCd == "0997") {
      sellingItem.scRt = 0;

      // 팔레트 기타 인경우 (기타하역료 금액을 8000원으로 셋팅)
      if (results2Row.commCd == "30000042" && results1Row.cntrSizCd == "20") {
        if (results1Row.cntrCount == 1) {
          // 컨테이너 사이즈가 20 이고 컨테이너 수량이 1인 경우에만  8000원으로 셋팅 ( 2008.04.23)
          sellingItem.sellAmt = 8000;
          sellingItem.vatAmt = sellingItem.sellAmt * 0.1;
          sellingItem.subSum = sellingItem.sellAmt + sellingItem.vatAmt;
        } else if (results1Row.cntrCount == 2) {
          // 컨테이너 사이즈가 20 이고 컨테이너 수량이 2인 경우에만  15000원으로 셋팅 ( 2008.05.19)
          sellingItem.sellAmt = 15000;
          sellingItem.vatAmt = sellingItem.sellAmt * 0.1;
          sellingItem.subSum = sellingItem.sellAmt + sellingItem.vatAmt;
        }
      }
    }
    addItems.push(sellingItem);
  }
  if (addItems.length) {
    ds_results4.insertJSON(ds_results4.getRowCount(), addItems);
    let rowCnt = ds_results4.getRowCount();
    tbx_totalRows4.setValue(rowCnt);
  }
  if (doButtonDisable) {
    scwin.f_buttonDisable();
  }
};

/**
 * method
 * @name f_calSc
 * @params {Number} row ds_results4의 rowIndex
 * @description 할증율 계산
 */
scwin.f_calSc = function (row) {
  let offInRate = 0; //하차입고료
  let devanningRate = 0; //적출료
  let paperSell20 = 0; //제지매출20
  let paperSell40 = 0; //제지매출40
  let bExistPaperSell = false; //제지매출 존재여부

  let allData = ds_results4.getAllJSON();
  for (let item of allData) {
    switch (item.sellItemCd) {
      case "0050":
        //하차입고료
        offInRate = $c.num.parseFloat($p, item.sellAmt);
        break;
      case "0179":
        //적출료
        devanningRate = $c.num.parseFloat($p, item.sellAmt);
        break;
      case "0278":
        //제지매출20
        paperSell20 = $c.num.parseFloat($p, item.sellAmt);
        bExistPaperSell = true;
        break;
      case "0279":
        //제지매출40
        paperSell40 = $c.num.parseFloat($p, item.sellAmt);
        bExistPaperSell = true;
        break;
    }
  }
  let rate = 0; //할증율
  let scRt = 0; //입력할증율
  let paperSell = Math.max(paperSell20, paperSell40); //제지매출중 큰값
  let results4Row = ds_results4.getRowJSON(row);
  let totSellAmt = null;
  switch (results4Row.sellItemCd) {
    //혹한 혹서 우천 설천 황천
    case "0093":
    case "0094":
    case "0095":
    case "0096":
    case "0097":
      rate = (offInRate + devanningRate) * 0.1;
      break;

    //위험물할증, 장척할증, 난작업할증
    case "0088":
    case "0100":
    case "0086":
    case "0092":
      scRt = $c.num.parseFloat($p, results4Row.scRt);
      rate = (offInRate + devanningRate) * scRt / 100;
      break;
    case "0098":
      //야간할증 황사할증
      rate = (offInRate + devanningRate) * 0.5;
      break;
    case "0089":
      //휴일할증
      if (bExistPaperSell) {
        rate = paperSell * 0.5;
      } else {
        rate = (offInRate + devanningRate) * 0.5;
      }
      break;
    case "0090":
      //토요할증
      if (bExistPaperSell) {
        rate = paperSell * 0.5;
      } else {
        rate = (offInRate + devanningRate) * 0.5;
      }
      break;
    case "0042":
      //보세운송수수료
      rate = $c.num.parseFloat($p, results4Row.sellUpr) * $c.num.parseFloat($p, results4Row.qty);
      ds_results4.setCellData(row, "sellVol", results4Row.qty);
      results4Row.sellVol = results4Row.qty;
      break;
    case "0256":
      //금액할인
      //공급가액
      totSellAmt = allData.reduce((sum, item) => sum + $c.num.parseFloat($p, item.sellAmt), 0); //매출금액 합
      scRt = $c.num.parseFloat($p, results4Row.scRt);
      rate = totSellAmt * scRt / 100;
      break;
    case "0967":
      //황사할증
      rate = Math.round((offInRate + devanningRate) * 0.5);
      ds_results4.setCellData(row, "scRt", 50); // 할증율
      break;
    case "0997":
      //기타하역료
      // 팔레트 기타 인경우 (기타하역료 금액을 8000원으로 셋팅)
      if (ds_results2.getCellData(gr_results2.getFocusedRowIndex(), "commCd") == "30000042") {
        // 컨테이너 사이즈가 20 이고 컨테이너 수량이 1인 경우에만  8000원으로 셋팅 ( 2008.04.23)
        let results1Row = ds_results1.getRowJSON(gr_results1.getFocusedRowIndex());
        if (results1Row.cntrSizCd == "20" && results1Row.cntrCount == 1) {
          rate = 8000;
        } else if (results1Row.cntrSizCd == "20" && results1Row.cntrCount == 2) {
          // 컨테이너 사이즈가 20 이고 컨테이너 수량이 2인 경우에만  15000원으로 셋팅 ( 2008.05.19)
          rate = 15000;
        } else {
          rate = $c.num.parseFloat($p, results4Row.sellUpr) * $c.num.parseFloat($p, results4Row.sellVol);
        }
      } else {
        rate = $c.num.parseFloat($p, results4Row.sellUpr) * $c.num.parseFloat($p, results4Row.sellVol);
      }
      break;
  }
  let sellVol = $c.num.parseFloat($p, results4Row.sellVol);
  if (sellVol != 0) {
    sellVol = rate / sellVol;
  }
  ds_results4.setCellData(row, "sellAmt", rate); //매출금액
  ds_results4.setCellData(row, "sellUpr", sellVol); //단가
  ds_results4.setCellData(row, "vatAmt", rate * 0.1); //부가세
};

/**
 * method
 * @name f_totalCal
 * @description 총합 계산
 */
scwin.f_totalCal = function () {
  let totalRateAmt = 0; //운송료
  let totalPrebilgRateAmt = 0; //선청구운송료
  let totalSellAmt = 0; //공급가액

  let results2Row = ds_results2.getRowJSON(gr_results2.getFocusedRowIndex());
  let filtered = ds_results3.getAllJSON().filter(item => item.mrn == results2Row.mrn && item.msn == results2Row.msn && item.hsn == results2Row.hsn);
  for (let item of filtered) {
    totalRateAmt += $c.num.parseFloat($p, item.sellAmt);
    totalPrebilgRateAmt += $c.num.parseFloat($p, item.prebilgSellAmt);
  }
  let allData = ds_results4.getAllJSON();
  for (let item of allData) {
    totalSellAmt += $c.num.parseFloat($p, item.sellAmt); //매출금액 합
  }
  let total = totalSellAmt + totalRateAmt - totalPrebilgRateAmt;
  let totalVat = total * 0.1;
  gr_results4.setFooterData("sumSellAmt", total);
  gr_results4.setFooterData("sumVatAmt", totalVat);
  gr_results4.setFooterData("sumSubSum", total + totalVat);
};

