/**
 * event
 * @name gr_results4_onviewchange
 * @description
 */
scwin.gr_results4_onviewchange = function (info) {
  const row = info.rowIndex;
  const value = info.newValue;
  const colid = info.colId;
  if (colid == "sellItemCd") {
    //제지매출20 ||  제지매출40  ||  중기일용료  ||  보통일용료  ||  장비사용료 || 보세운송수수료 ||이송료
    switch (ds_results4.getCellData(row, "sellItemCd")) {
      case "0278":
      case "0279":
      case "0009":
      case "0008":
      case "0003":
      case "0042":
      case "0051":
        ds_results4.setCellData(row, "sellVol", 0);
        ds_results4.setCellData(row, "sellAmt", 0);
        ds_results4.setCellData(row, "qty", 0);
        ds_results4.setCellData(row, "wt", 0);
        ds_results4.setCellData(row, "cbm", 0);
        ds_results4.setCellData(row, "vatAmt", 0);
        ds_results4.setCellData(row, "subSum", 0);
        break;
    }
  }
  gr_results4.setColumnReadOnly("eqKndCd", false); //"Upper";
  if (info.oldValue != value) {
    //인서트일때 왼쪽 데이터가 바뀌면 오른쪽 그리드에도 적용해야한다
    scwin.gr_result4_currentRow = row;
    if (colid == "eqKndCd") {
      ds_results4.setCellData(row, "eqKndCd", "");
      ds_results4.setCellData(row, "eqKndNm", "");
      ds_results4.setCellData(row, "eqNrmNm", "");
      ds_results4.setCellData(row, "eqNrmCd", "");
      scwin.f_openCommonPopUp(2, value, '', 'T', 'F');
    } else if (colid == "eqKndNm") {
      ds_results4.setCellData(row, "eqKndNm", "");
      ds_results4.setCellData(row, "eqKndCd", "");
      ds_results4.setCellData(row, "eqNrmNm", "");
      ds_results4.setCellData(row, "eqNrmCd", "");
      scwin.f_openCommonPopUp(2, '', value, 'T', 'F');
    }
  }
};

/**
 * event
 * @name gr_results4_onafteredit
 * @description
 */
scwin.gr_results4_onafteredit = function (row, col, value) {
  const colid = gr_results4.getColumnID(col);
  switch (colid) {
    case "sellUpr":
    case "scRt":
    case "sellVol":
    case "qty":
    case "wt":
    case "cbm":
      if (value == "" || isNaN(value)) {
        ds_results4.setCellData(row, colid, "0");
      }
      break;
  }
};

