/**
 * event
 * @name btn_deleteAll_onclick
 * @description
 */
scwin.btn_deleteAll_onclick = function (e) {
  ds_results4.setBroadcast(false);
  for (let idx = ds_results4.getRowCount() - 1; idx >= 0; --idx) {
    if (ds_results4.getRowStatus(idx) == "C") {
      ds_results4.removeRow(idx);
    } else {
      ds_results4.deleteRow(idx);
    }
  }
  let rowCnt = ds_results4.getRowCount();
  tbx_totalRows4.setValue(rowCnt);
  ds_results4.setBroadcast(true, true);
};

